return items.map((item) => {
  let raw = item.json.candidates?.[0]?.content?.parts?.[0]?.text ?? "";
  if (!raw) {
    throw new Error("Keine Gemini-Antwort gefunden");
  }

  raw = raw
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();
  const parsed = JSON.parse(raw);

  const summariesFirestore = parsed.summaries.map((summary) => ({
    mapValue: {
      fields: {
        id: { stringValue: summary.id },
        order: { integerValue: summary.order },
        title: { stringValue: summary.title },
        cookingTimeMinutes: { integerValue: summary.cookingTimeMinutes },
        cookingTimeLabel: { stringValue: summary.cookingTimeLabel },
        tags: {
          arrayValue: {
            values: (summary.tags || []).map((tag) => ({ stringValue: tag })),
          },
        },
      },
    },
  }));

  const detailsFirestore = Object.fromEntries(
    Object.entries(parsed.details).map(([key, detail]) => {
      const fields = {
        description: { stringValue: detail.description },
        helperLabels: {
          arrayValue: {
            values: (detail.helperLabels || []).map((label) => ({
              stringValue: label,
            })),
          },
        },
        nutritionalInformation: {
          mapValue: {
            fields: {
              energyKcal: {
                integerValue: detail.nutritionalInformation.energyKcal,
              },
              proteinGrams: {
                integerValue: detail.nutritionalInformation.proteinGrams,
              },
              fatGrams: {
                integerValue: detail.nutritionalInformation.fatGrams,
              },
              carbsGrams: {
                integerValue: detail.nutritionalInformation.carbsGrams,
              },
            },
          },
        },
        primaryIngredients: {
          arrayValue: {
            values: (detail.primaryIngredients || []).map((ing) => ({
              mapValue: {
                fields: {
                  name: { stringValue: ing.name },
                  amount: { doubleValue: ing.amount },
                  unit: { stringValue: ing.unit },
                  source: { stringValue: ing.source },
                },
              },
            })),
          },
        },
        hearts: { integerValue: detail.hearts },
      };

      if ((detail.extraIngredients || []).length) {
        fields.extraIngredients = {
          arrayValue: {
            values: detail.extraIngredients.map((ing) => ({
              mapValue: {
                fields: {
                  name: { stringValue: ing.name },
                  amount: { doubleValue: ing.amount },
                  unit: { stringValue: ing.unit },
                  source: { stringValue: ing.source },
                },
              },
            })),
          },
        };
      }

      if ((detail.directions || []).length) {
        fields.directions = {
          arrayValue: {
            values: detail.directions.map((step) => ({
              mapValue: {
                fields: {
                  order: { integerValue: step.order },
                  title: { stringValue: step.title },
                  instruction: { stringValue: step.instruction },
                  assignedChefIndex: { integerValue: step.assignedChefIndex },
                },
              },
            })),
          },
        };
      }

      return [
        key,
        {
          mapValue: { fields },
        },
      ];
    }),
  );

  return {
    json: {
      summariesFirestore,
      detailsFirestore,
      requestId: item.json.requestId,
    },
  };
});

const ipDoc = $node["Get IP Quota"].json;
const globalDoc = $node["Get Global Quota"].json;

const ipCount = Number(ipDoc?.fields?.count?.integerValue || 0);
const globalCount = Number(globalDoc?.fields?.count?.integerValue || 0);

const remainingIp = Math.max(0, 3 - ipCount);
const remainingGlobal = Math.max(0, 12 - globalCount);

return [{
  json: {
    ipCount,
    globalCount,
    quota: {
      remainingIp,
      remainingGlobal,
      dateKey: $node["Extract client IP"].json.dateKey,
      timeZone: "Europe/Berlin"
    }
  }
}];

