const parsed = $node["Message a model"].json.candidates?.[0]?.content?.parts?.[0]?.text ?? "";
const clean = parsed.replace(/```json/gi, "").replace(/```/g, "").trim();
const data = JSON.parse(clean);

const cuisine = ($node["Webhook"].json.body.payload.preferences.cuisine || "").toString();
const diet = ($node["Webhook"].json.body.payload.preferences.dietPreferences || [])[0] || "No preferences";
const cookTime = $node["Webhook"].json.body.payload.preferences.cookTime;

const cookTimeTagMap = { under20: "Quick", "25to40": "Medium", over45: "Complex" };
const cookTimeTag = cookTimeTagMap[cookTime] || "Medium";

const createdAt = new Date().toISOString();

const libraryRecipes = data.summaries.map((summary) => {
  const detail = data.details[summary.id] || {};
  const hearts = Number(detail.hearts || 0);

  const recipe = {
    title: summary.title,
    cookingTimeMinutes: summary.cookingTimeMinutes,
    cookingTimeLabel: summary.cookingTimeLabel,
    tags: summary.tags || [],
    cuisine,
    diet,
    cookTimeTag,
    hearts,
    thumbnail: "",
    createdAt,
    description: detail.description || "",
    helperLabels: detail.helperLabels || [],
    nutritionalInformation: detail.nutritionalInformation || {
      energyKcal: 0,
      proteinGrams: 0,
      fatGrams: 0,
      carbsGrams: 0
    },
    primaryIngredients: detail.primaryIngredients || [],
    extraIngredients: detail.extraIngredients || [],
    directions: detail.directions || []
  };

  const firestoreBody = {
    fields: {
      title: { stringValue: recipe.title },
      cookingTimeMinutes: { integerValue: String(recipe.cookingTimeMinutes) },
      cookingTimeLabel: { stringValue: recipe.cookingTimeLabel },
      tags: { arrayValue: { values: recipe.tags.map(tag => ({ stringValue: tag })) } },
      cuisine: { stringValue: recipe.cuisine },
      diet: { stringValue: recipe.diet },
      cookTimeTag: { stringValue: recipe.cookTimeTag },
      thumbnail: { stringValue: recipe.thumbnail },
      createdAt: { timestampValue: recipe.createdAt },
      description: { stringValue: recipe.description },
      helperLabels: { arrayValue: { values: recipe.helperLabels.map(label => ({ stringValue: label })) } },
      nutritionalInformation: {
        mapValue: { fields: {
          energyKcal: { integerValue: recipe.nutritionalInformation.energyKcal },
          proteinGrams: { integerValue: recipe.nutritionalInformation.proteinGrams },
          fatGrams: { integerValue: recipe.nutritionalInformation.fatGrams },
          carbsGrams: { integerValue: recipe.nutritionalInformation.carbsGrams }
        }}
      },
      primaryIngredients: {
        arrayValue: { values: recipe.primaryIngredients.map(ing => ({
          mapValue: { fields: {
            name: { stringValue: ing.name },
            amount: { doubleValue: ing.amount },
            unit: { stringValue: ing.unit },
            source: { stringValue: ing.source }
          }}
        })) }
      },
      extraIngredients: {
        arrayValue: { values: recipe.extraIngredients.map(ing => ({
          mapValue: { fields: {
            name: { stringValue: ing.name },
            amount: { doubleValue: ing.amount },
            unit: { stringValue: ing.unit },
            source: { stringValue: ing.source }
          }}
        })) }
      },
      directions: {
        arrayValue: { values: recipe.directions.map(step => ({
          mapValue: { fields: {
            order: { integerValue: step.order },
            title: { stringValue: step.title },
            instruction: { stringValue: step.instruction },
            assignedChefIndex: { integerValue: step.assignedChefIndex }
          }}
        })) }
      },
      ...(hearts > 0 ? { hearts: { integerValue: String(hearts) } } : {})
    }
  };

  return { json: { firestoreBody } };
});

return libraryRecipes;

